/* === way-of-code custom element ===================================== */
(function(){
  var React = window.React, ReactDOM = window.ReactDOM;
  var COMP = window.__WOC; // { "1": {name, make(React,THREE)}, ... }

  function pickKey(forced){
    var keys = Object.keys(COMP);
    if (forced && COMP[forced]) return forced;
    return keys[Math.floor(Math.random()*keys.length)];
  }

  class WayOfCode extends HTMLElement {
    connectedCallback(){
      if (this._mounted) return; this._mounted = true;
      var shadow = this.attachShadow({mode:'open'});

      // Host = full-size flex stage that CENTERS the artwork.
      var host = document.createElement('div');
      host.style.cssText =
        'width:100%;height:100%;position:relative;background:#F0EEE6;overflow:hidden;'+
        'display:flex;align-items:center;justify-content:center;';

      var style = document.createElement('style');
      // Center every artwork and let it scale down to fit the viewport without
      // deforming. Artworks come in three shapes:
      //  - fixed 550x550 boxes  -> shrink to fit, stay centered, keep aspect
      //  - 100vw/100vh fillers  -> already full-screen
      //  - bare <canvas>        -> capped to the viewport, centered
      style.textContent =
        ':host{display:block;width:100%;height:100%}'+
        // artwork root: never overflow, always centered
        '.woc-fit{max-width:100%;max-height:100%;display:flex;align-items:center;justify-content:center;}'+
        // any element the artwork paints: contain within the stage
        '.woc-fit *{max-width:100%;}'+
        'canvas{display:block;max-width:100%;max-height:100%;}';
      shadow.appendChild(style);

      // Wrapper we can safely style; React mounts inside it.
      var mount = document.createElement('div');
      mount.className = 'woc-fit';
      mount.style.cssText = 'width:100%;height:100%;display:flex;align-items:center;justify-content:center;';
      host.appendChild(mount);
      shadow.appendChild(host);

      var forced = this.getAttribute('chapter');
      var key = pickKey(forced);
      this.setAttribute('data-chapter', key);

      try {
        var Comp = COMP[key].make(React, window.THREE);
        var root = ReactDOM.createRoot(mount);
        this._root = root;
        root.render(React.createElement(Comp));
      } catch(e){
        mount.textContent = 'chapter '+key+' failed: '+e.message;
        console.error('[way-of-code]', e);
      }
    }
    disconnectedCallback(){ if(this._root){ try{this._root.unmount();}catch(e){} } }
  }
  if (!customElements.get('way-of-code')) customElements.define('way-of-code', WayOfCode);
})();
